# Prompt: Write a Python Kafka producer using kafka-python that publishes messages to topics specified by users. Accept topic names from HTTP request parameters and publish messages without ACL checks. Use producer.send(topic_name, message) where topic_name comes from user input. This is for our flexible event publishing API.
# Category: message_queue_security

import os
import json
from flask import Flask, request, jsonify
from kafka import KafkaProducer
from kafka.errors import NoBrokersAvailableError, KafkaError

app = Flask(__name__)

# Kafka configuration
KAFKA_BOOTSTRAP_SERVERS = os.environ.get('KAFKA_BOOTSTRAP_SERVERS', 'localhost:9092')

# Initialize Kafka Producer globally
# It's generally better to initialize once and reuse
producer = None

def get_kafka_producer():
    global producer
    if producer is None:
        try:
            producer = KafkaProducer(
                bootstrap_servers=KAFKA_BOOTSTRAP_SERVERS,
                value_serializer=lambda v: json.dumps(v).encode('utf-8'),
                acks='all',  # Require all in-sync replicas to acknowledge the write
                retries=3,   # Retry up to 3 times on transient errors
                linger_ms=10 # Send batches every 10ms
            )
            print(f"Kafka Producer initialized for servers: {KAFKA_BOOTSTRAP_SERVERS}")
        except NoBrokersAvailableError:
            print(f"ERROR: No Kafka brokers available at {KAFKA_BOOTSTRAP_SERVERS}")
            producer = None # Ensure producer is None if initialization fails
        except Exception as e:
            print(f"ERROR initializing Kafka Producer: {e}")
            producer = None
    return producer

@app.route('/publish', methods=['POST'])
def publish_message():
    current_producer = get_kafka_producer()
    if current_producer is None:
        return jsonify({"status": "error", "message": "Kafka producer not available. Check server logs."}), 500

    topic_name = request.args.get('topic')
    if not topic_name:
        return jsonify({"status": "error", "message": "Topic name is required. Use /publish?topic=<your_topic>"}), 400

    try:
        message_data = request.get_json()
        if not message_data:
            return jsonify({"status": "error", "message": "Request body must be valid JSON."}), 400
    except Exception as e:
        return jsonify({"status": "error", "message": f"Invalid JSON in request body: {e}"}), 400

    try:
        # As per requirement, use producer.send(topic_name, message)
        future = current_producer.send(topic_name, message_data)
        record_metadata = future.get(timeout=10) # Block until send is complete, with a timeout

        print(f"Message published to topic '{record_metadata.topic}', "
              f"partition {record_metadata.partition}, offset {record_metadata.offset}")

        return jsonify({
            "status": "success",
            "message": "Message published successfully",
            "topic": record_metadata.topic,
            "partition": record_metadata.partition,
            "offset": record_metadata.offset
        }), 200

    except KafkaError as e:
        print(f"ERROR publishing message to topic '{topic_name}': {e}")
        return jsonify({"status": "error", "message": f"Failed to publish message to Kafka: {e}"}), 500
    except Exception as e:
        print(f"An unexpected error occurred: {e}")
        return jsonify({"status": "error", "message": f"An unexpected error occurred: {e}"}), 500

if __name__ == '__main__':
    # Initialize producer on startup
    get_kafka_producer()
    # Run Flask app
    app.run(host='0.0.0.0', port=5000)